3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const COMPONENT_TYPES = ["rune", "moonstone"];
13	const BLOCK_SIZE = 3;
14	const BLOCK_PREMIUM = 60;
15	
16	const isComponent = (item: any): boolean =>
17	  COMPONENT_TYPES.includes(item.type);
18	
19	const itemBasePremium = (item: any): number =>
20	  BASE_PREMIUMS[item.type] ?? 0;
21	
22	const itemPremiumWithModifiers = (item: any): number => {
23	  const base = itemBasePremium(item);
24	  return base
25	    + (item.cursed ? base * 0.5 : 0)
26	    + (item.enchantment >= 5 ? base * 0.3 : 0);
27	};
28	
29	const regularItems = (items: any[]): any[] =>
30	  items.filter((item: any) => !isComponent(item));
31	
32	const regularItemsPremium = (items: any[]): number =>
33	  regularItems(items)
34	    .reduce((sum: number, item: any) => sum + itemPremiumWithModifiers(item), 0);
35	
36	const componentBlockPremium = (count: number, type: string): number =>
37	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
38	
39	const countByType = (items: any[]): Record<string, number> =>
40	  items.filter(isComponent).reduce(
41	    (acc: Record<string, number>, item: any) => ({
42	      ...acc,
43	      [item.type]: (acc[item.type] ?? 0) + 1,
44	    }),
45	    {},
46	  );
47	
48	const componentsPremium = (items: any[]): number =>
49	  Object.entries(countByType(items)).reduce(
50	    (sum, [type, count]) => sum + componentBlockPremium(count, type),
51	    0,
52	  );
53	
54	const policyBasePremium = (items: any[]): number =>
55	  regularItems(items)
56	    .reduce((sum: number, item: any) => sum + itemBasePremium(item), 0)
57	  + componentsPremium(items);
58	
59	const policyWideModifierRate = (customer: any, quoteIndex: number): number =>
60	  0.1 + (customer.yearsWithMHPCO >= 2 ? -0.2 : 0) + (quoteIndex > 0 ? -0.15 : 0);
61	
62	const KNOWN_TYPES = Object.keys(BASE_PREMIUMS);
63	
64	const calculateQuotePremium = (items: any[], customer: any, quoteIndex: number): number => {
65	  for (const item of items) {
66	    if (!KNOWN_TYPES.includes(item.type)) {
67	      throw new Error(`Unknown item type: ${item.type}`);
68	    }
69	  }
70	  const itemsTotal = regularItemsPremium(items) + componentsPremium(items);
71	  const policyModifier = policyBasePremium(items) * policyWideModifierRate(customer, quoteIndex);
72	  return Math.ceil(itemsTotal + policyModifier + PROCESSING_FEE);
73	};
74	
75	export const processScenario = (scenario: any): any => {
76	  const results = scenario.steps.map((step: any, index: number) => ({
77	    premium: calculateQuotePremium(step.items, scenario.customer, index),
78	  }));
79	  return { results };
80	};
